  function getAuthHeaders() { const key = sessionStorage.getItem("cpa_mgmt_key") || localStorage.getItem("cpa_mgmt_key") || ""; return key ? { Authorization: "Bearer " + key } : {}; }
  async function apiFetch(path, options) { const init = options ? { ...options } : {}; init.headers = { ...getAuthHeaders(), ...(init.headers || {}) }; const response = await fetch(path, init); if (response.status === 401 || response.status === 403) { const banner = $("#auth-banner"); if (banner) banner.hidden = false; throw new Error("auth"); } const body = await response.json().catch(() => ({})); if (!response.ok) throw new Error(body.error || "HTTP " + response.status); return body; }
  function showToast(message) { const toast = $("#toast"); if (!toast) return; toast.textContent = message; toast.hidden = false; setTimeout(() => { toast.hidden = true; }, 5000); }
  function fmtMs(value) { return value == null || Number.isNaN(value) ? "—" : value >= 1000 ? (value / 1000).toFixed(2) + "s" : Math.round(value) + "ms"; }
  function fmtNum(value) { return value == null || Number.isNaN(value) ? "—" : String(Math.round(value)); }
