  function metricValue(row) { return row[comparison.metric] || 0; }
function metricAvailable(row) { if (comparison.metric === "p95_ttft_ms") return (row.ttft_observed || 0) > 0; if (comparison.metric === "avg_stream_rate_tps") return (row.count || 0) > 0; return (row.count || 0) > 0; }
