  function renderComparison(report) { comparison.report = report; const direction = comparison.metric === "p95_ttft_ms" || comparison.metric === "avg_latency_ms" ? 1 : -1; const rows = [...(report.rows || [])].sort((a, b) => (metricValue(a) - metricValue(b)) * direction); comparison.lastRows = rows; const cards = $("#compare-kpis"); cards.innerHTML = ""; const subject = rows[0]; const kpiNote = $("#compare-kpi-note"); if (kpiNote) { kpiNote.textContent = subject ? "Top-ranked subject by " + comparison.metric + " — four-raw-card view." : ""; } if (subject) for (const [label, field, format] of [["TTFT P95", "p95_ttft_ms", fmtMs], ["TPS", "avg_stream_rate_tps", fmtTps], ["Success rate", "success_rate", fmtPct], ["Total response time", "avg_latency_ms", fmtMs]]) { const card = document.createElement("div"); card.className = "kpi-card"; const labelEl = document.createElement("span"); labelEl.className = "kpi-label"; labelEl.textContent = label; const valueEl = document.createElement("span"); valueEl.className = "kpi-value"; valueEl.textContent = field === "p95_ttft_ms" ? ((subject.ttft_observed || 0) > 0 ? format(subject.p95_ttft_ms) : "—") : format(subject[field]); const mutedEl = document.createElement("span"); mutedEl.className = "muted"; mutedEl.textContent = subject.count + " samples"; card.append(labelEl, valueEl, mutedEl); cards.appendChild(card); } const tbody = $("#compare-table tbody"); tbody.innerHTML = ""; rows.forEach((row, index) => { const tr = document.createElement("tr"); const trendRaw = row.trend_24h_over_24h; const trendCell = trendAvailable(row) ? (trendRaw > .02 ? "↑" : trendRaw < -.02 ? "↓" : "→") : "—"; const trendPct = trendAvailable(row) ? fmtPct(trendRaw) : "—"; [index + 1, row.label, formatMetricCell(row), row.count, (row.count || 0) > 0 ? fmtPct(row.success_rate) : "—", trendCell, trendPct].forEach((text) => { const td = document.createElement("td"); td.textContent = text; tr.appendChild(td); }); tbody.appendChild(tr); }); $("#compare-empty").hidden = rows.length > 0; renderNormalizedChart(rows); }
  function renderNormalizedChart(rows) { const body = $("#compare-chart-body"); const tooltip = $("#compare-tooltip"); if (charts.compare) charts.compare.destroy(); body.innerHTML = ""; if (tooltip) { tooltip.hidden = true; tooltip.replaceChildren(); } const times = [...new Set(rows.flatMap((row) => (row.series || []).map((point) => point.at)))].sort(); if (!times.length) return; const data = [times.map((at) => new Date(at).getTime() / 1000)]; const series = [{ label: "Time" }]; const rawsByIndex = []; rows.forEach((row, index) => { const values = (row.series || []).map((point) => point.value); const min = Math.min(...values), max = Math.max(...values); const raws = []; data.push(times.map((at) => { const point = (row.series || []).find((item) => item.at === at); if (!point) { raws.push(null); return null; } raws.push(point.value); return max === min ? .5 : (point.value - min) / (max - min); })); rawsByIndex.push(raws); series.push({ label: row.label, stroke: COLORS[index % COLORS.length], width: 2 }); }); const clearTooltip = () => { if (!tooltip) return; tooltip.hidden = true; tooltip.replaceChildren(); }; const fillTooltip = (dataIdx) => { if (!tooltip) return; const at = new Date(data[0][dataIdx] * 1000); tooltip.replaceChildren(); const header = document.createElement("div"); header.className = "compare-tooltip-header"; header.textContent = at.toISOString().replace("T", " ").slice(0, 19) + "Z"; tooltip.appendChild(header); const rowsFragment = document.createDocumentFragment(); rows.forEach((row, i) => { const raw = rawsByIndex[i][dataIdx]; const normalized = data[i + 1][dataIdx]; const line = document.createElement("div"); line.className = "compare-tooltip-row"; const swatch = document.createElement("span"); swatch.className = "compare-tooltip-swatch"; swatch.style.background = COLORS[i % COLORS.length]; const label = document.createElement("span"); label.className = "compare-tooltip-label"; label.textContent = row.label; const values = document.createElement("span"); values.className = "compare-tooltip-values"; values.textContent = raw == null ? "—" : formatRaw(raw) + " · " + (normalized == null ? "—" : normalized.toFixed(3)); line.append(swatch, label, values); rowsFragment.appendChild(line); }); tooltip.appendChild(rowsFragment); tooltip.hidden = false; }; const placeTooltip = (pageX, pageY) => { if (!tooltip) return; const parent = body.getBoundingClientRect(); const padding = 8; const w = tooltip.offsetWidth || 200; const h = tooltip.offsetHeight || 80; const left = Math.min(parent.left + parent.width - w - padding, Math.max(parent.left + padding, pageX)); const top = Math.max(parent.top + padding, pageY - h - padding); tooltip.style.left = (left - parent.left) + "px"; tooltip.style.top = (top - parent.top) + "px"; }; charts.compare = new uPlot({ width: body.clientWidth || 600, height: 240, scales: { x: { time: true }, y: { range: [0, 1] } }, cursor: { drag: { x: false, y: false }, points: { size: 6 } }, series, axes: [{ stroke: "var(--fg-mute)" }, { stroke: "var(--fg-mute)", label: "normalized (raw on hover)" }], hooks: { setCursor: [ (u) => { const idx = u.cursor.idx; if (idx == null || data[0][idx] == null) { clearTooltip(); return; } fillTooltip(idx); const evt = u.cursor.event; const pageX = evt && evt.clientX != null ? evt.clientX : body.getBoundingClientRect().left + u.cursor.left; const pageY = evt && evt.clientY != null ? evt.clientY : body.getBoundingClientRect().top + u.cursor.top; placeTooltip(pageX, pageY); } ], setSelect: [ (u) => { u.setSelect({ left: 0, top: 0, width: 0, height: 0 }); } ] } }, data, body); body.addEventListener("mouseleave", () => clearTooltip()); }
  function csvEscape(value) { if (value == null) return ""; const str = String(value); if (str.includes(",") || str.includes("\"") || str.includes("\n") || str.includes("\r")) { return "\"" + str.replace(/"/g, "\"\"") + "\""; } return str; }
  function downloadComparisonCsv() { const report = comparison.report; if (!report || !report.rows || !report.rows.length) { showCompareError("Load a comparison before exporting CSV."); return; } const header = ["rank", "subject", "metric", "metric_value", "samples", "success_rate", "p95_ttft_ms", "p95_ttft_observed", "avg_stream_rate_tps", "avg_latency_ms", "trend_24h_over_24h", "window_start", "raw_value"]; const lines = [header.join(",")]; const rows = [...report.rows].sort((a, b) => (metricValue(a) - metricValue(b)) * (comparison.metric === "p95_ttft_ms" || comparison.metric === "avg_latency_ms" ? 1 : -1)); const cellFor = (row) => metricAvailable(row) ? metricValue(row) : ""; rows.forEach((row, index) => { const series = row.series && row.series.length ? row.series : [{ at: null, value: null }]; const p95Cell = (row.ttft_observed || 0) > 0 ? row.p95_ttft_ms : ""; series.forEach((point) => { lines.push([index + 1, row.label, comparison.metric, cellFor(row), row.count, row.success_rate, p95Cell, row.ttft_observed ?? 0, row.avg_stream_rate_tps, row.avg_latency_ms, row.trend_24h_over_24h, point.at ?? "", point.value ?? ""].map(csvEscape).join(",")); }); }); const csv = "\uFEFF" + lines.join("\r\n"); const blob = new Blob([csv], { type: "text/csv;charset=utf-8" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); const stamp = new Date().toISOString().slice(0, 10); a.href = url; a.download = "compare-" + comparison.kind + "-" + comparison.metric + "-" + comparison.range + "-" + stamp + ".csv"; document.body.appendChild(a); a.click(); document.body.removeChild(a); setTimeout(() => URL.revokeObjectURL(url), 0); }
  async function createShare() { if (!comparison.report) { showCompareError("Load a comparison before sharing."); return; } try { const payload = { kind: comparison.kind, ids: [...comparison.selected], range: comparison.range, from: comparison.from ? new Date(comparison.from).toISOString() : "", to: comparison.to ? new Date(comparison.to).toISOString() : "", metric: comparison.metric, require_token: $("#compare-token").checked, expires_in: $("#compare-expires").value }; const result = await apiFetch(MGMT + "/share", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(payload) }); const path = result.url || result.short_url; const absolute = location.origin + path; if (navigator.clipboard) await navigator.clipboard.writeText(absolute); showToast("Share link copied: " + absolute); } catch (error) { showCompareError(error.message); } }
  async function loadSharedSnapshot(id, token) { comparison.shareOnly = true; try { const query = new URLSearchParams({ id }); if (token) query.set("token", token); const response = await fetch(BASE + "/share-data?" + query, { credentials: "same-origin" }); const body = await response.json(); if (!response.ok) throw new Error(body.error || "Shared snapshot not found"); comparison.metric = body.metric; $("#compare-section").hidden = false; $("#compare-btn").hidden = true; $("#share-btn").hidden = true; $("#compare-close").hidden = true; $("#compare-subjects").hidden = true; $("#compare-kind").hidden = true; $("#compare-metric").hidden = true; $("#compare-range").hidden = true; $("#compare-from").hidden = true; $("#compare-to").hidden = true; $("#compare-expires").hidden = true; $("#compare-token").parentElement.hidden = true; $("#csv-btn").hidden = true; $("#range-selector").hidden = true; $("#refresh-selector").hidden = true; $("#refresh-btn").hidden = true; $("#kpi-section").hidden = true; $("#insight-section").hidden = true; $("#chart-ttft").hidden = true; $("#chart-tps").hidden = true; $("#chart-error").hidden = true; $("#model-table").closest(".table-section").hidden = true; $("#drill-panel").hidden = true; const modeLabel = $("#mode-label"); if (modeLabel) { const created = body.created_at ? new Date(body.created_at).toISOString().replace("T", " ").slice(0, 19) + "Z" : ""; const expires = body.expires_at ? " · expires " + new Date(body.expires_at).toISOString().slice(0, 10) : ""; modeLabel.textContent = created ? "Shared snapshot · " + created + expires : "Shared snapshot"; modeLabel.hidden = false; } const count = $("#compare-count"); if (count) { const subjectCount = (body.rows || []).length; count.textContent = "Read-only view of " + subjectCount + " subjects. Comparison is locked to the snapshot data."; } renderComparison(body); if (token) history.replaceState(null, "", location.pathname + "?id=" + encodeURIComponent(id)); } catch (error) { showToast(error.message); } }
  function init() { $("#compare-btn").addEventListener("click", openComparison); $("#share-btn").addEventListener("click", createShare); $("#csv-btn").addEventListener("click", downloadComparisonCsv); $("#compare-kind").addEventListener("change", (event) => { if (comparison.shareOnly) return; comparison.kind = event.target.value; comparison.selected.clear(); renderSubjectPicker(); }); $("#compare-metric").addEventListener("change", (event) => { if (comparison.shareOnly) return; comparison.metric = event.target.value; loadComparison(); }); $("#compare-range").addEventListener("change", (event) => { if (comparison.shareOnly) return; comparison.range = event.target.value; $("#compare-from").hidden = event.target.value !== "custom"; $("#compare-to").hidden = event.target.value !== "custom"; loadComparison(); }); $("#compare-from").addEventListener("change", (event) => { if (comparison.shareOnly) return; comparison.from = event.target.value; loadComparison(); }); $("#compare-to").addEventListener("change", (event) => { if (comparison.shareOnly) return; comparison.to = event.target.value; loadComparison(); }); const params = new URLSearchParams(location.search); if (params.has("id")) loadSharedSnapshot(params.get("id"), params.get("token")); }
